// No leads to sync
return [{
  json: {
    success: true,
    message: 'No qualified leads to sync',
    leads_processed: 0
  }
}];

// Build Kommo Payload Node
// FIX #3: Use real Kommo status names instead of lead type labels

const leadData = $input.item.json;

// Kommo env
const KOMMO_PIPELINE_ID = $env.KOMMO_PIPELINE_ID;
const KOMMO_STATUS_INITIAL_CONTACT = $env.KOMMO_STATUS_INITIAL_CONTACT;
const KOMMO_STATUS_DISCUSSIONS = $env.KOMMO_STATUS_DISCUSSIONS;
const KOMMO_STATUS_DECISION_MAKING = $env.KOMMO_STATUS_DECISION_MAKING;
const KOMMO_STATUS_LOST = $env.KOMMO_STATUS_LOST;
const KOMMO_RESPONSIBLE_USER_ID = $env.KOMMO_RESPONSIBLE_USER_ID;

// Status names from env (FIX #3)
const KOMMO_STATUS_NAME_INITIAL_CONTACT = $env.KOMMO_STATUS_NAME_INITIAL_CONTACT || 'Первичный контакт';
const KOMMO_STATUS_NAME_DISCUSSIONS = $env.KOMMO_STATUS_NAME_DISCUSSIONS || 'Переговоры';
const KOMMO_STATUS_NAME_DECISION_MAKING = $env.KOMMO_STATUS_NAME_DECISION_MAKING || 'Принимается решение';
const KOMMO_STATUS_NAME_LOST = $env.KOMMO_STATUS_NAME_LOST || 'Закрыто и не реализовано';

const KOMMO_LEAD_TYPE_FIELD_ID = $env.KOMMO_LEAD_TYPE_FIELD_ID;
const KOMMO_PRIORITY_FIELD_ID = $env.KOMMO_PRIORITY_FIELD_ID;
const KOMMO_CONFIDENCE_FIELD_ID = $env.KOMMO_CONFIDENCE_FIELD_ID;
const KOMMO_PUBLIC_NUMBER_FIELD_ID = $env.KOMMO_PUBLIC_NUMBER_FIELD_ID;
const KOMMO_CATEGORY_FIELD_ID = $env.KOMMO_CATEGORY_FIELD_ID;
const KOMMO_ACTION_FIELD_ID = $env.KOMMO_ACTION_FIELD_ID;

// Status mapping: lead_type -> status_id
const statusIdMap = {
  hot: KOMMO_STATUS_INITIAL_CONTACT,
  warm: KOMMO_STATUS_DISCUSSIONS,
  cold: KOMMO_STATUS_DECISION_MAKING,
  spam: KOMMO_STATUS_LOST,
};

// FIX #3: Status name mapping: status_id -> status_name (from env)
const statusNameMap = {
  [KOMMO_STATUS_INITIAL_CONTACT]: KOMMO_STATUS_NAME_INITIAL_CONTACT,
  [KOMMO_STATUS_DISCUSSIONS]: KOMMO_STATUS_NAME_DISCUSSIONS,
  [KOMMO_STATUS_DECISION_MAKING]: KOMMO_STATUS_NAME_DECISION_MAKING,
  [KOMMO_STATUS_LOST]: KOMMO_STATUS_NAME_LOST,
};

const leadTypeLabelMap = {
  hot: 'Горячий',
  warm: 'Теплый',
  cold: 'Холодный',
  spam: 'Нецелевой',
};

const priorityLabelMap = {
  high: 'Высокий',
  medium: 'Средний',
  low: 'Низкий',
};

const actionLabelMap = {
  call: 'Позвонить',
  email: 'Написать',
  reject: 'Отклонить',
  archive: 'В архив',
};

const statusId = statusIdMap[leadData.lead_type] || KOMMO_STATUS_INITIAL_CONTACT;
const isSpam = leadData.lead_type === 'spam';

// FIX #3: Use status name from Kommo, not lead type label
const statusName = statusNameMap[statusId] || 'Неизвестный статус';

const kommoPayload = {
  name: `${leadData.public_number || 'LQ'} — ${leadData.contact_name || 'Неизвестный контакт'}`,
  price: 0,
  pipeline_id: Number(KOMMO_PIPELINE_ID),
  status_id: Number(statusId),
  responsible_user_id: Number(KOMMO_RESPONSIBLE_USER_ID),
  custom_fields_values: [
    {
      field_id: Number(KOMMO_LEAD_TYPE_FIELD_ID),
      values: [{ value: leadTypeLabelMap[leadData.lead_type] || 'Холодный' }],
    },
    {
      field_id: Number(KOMMO_PRIORITY_FIELD_ID),
      values: [{ value: priorityLabelMap[leadData.priority] || 'Низкий' }],
    },
    {
      field_id: Number(KOMMO_CONFIDENCE_FIELD_ID),
      values: [{ value: String(leadData.confidence ?? 0) }],
    },
    {
      field_id: Number(KOMMO_PUBLIC_NUMBER_FIELD_ID),
      values: [{ value: leadData.public_number }],
    },
    ...(leadData.category && KOMMO_CATEGORY_FIELD_ID ? [{
      field_id: Number(KOMMO_CATEGORY_FIELD_ID),
      values: [{ value: leadData.category }],
    }] : []),
    ...(leadData.suggested_action && KOMMO_ACTION_FIELD_ID ? [{
      field_id: Number(KOMMO_ACTION_FIELD_ID),
      values: [{ value: actionLabelMap[leadData.suggested_action] || leadData.suggested_action }],
    }] : []),
  ],
  _embedded: {
    contacts: [{
      name: leadData.contact_name || 'Неизвестный контакт',
      ...(leadData.contact_phone || leadData.contact_email
        ? {
            custom_fields_values: [
              ...(leadData.contact_phone ? [{
                field_code: 'PHONE',
                values: [{ value: leadData.contact_phone, enum_code: 'WORK' }],
              }] : []),
              ...(leadData.contact_email ? [{
                field_code: 'EMAIL',
                values: [{ value: leadData.contact_email, enum_code: 'WORK' }],
              }] : []),
            ],
          }
        : {}
      ),
    }],
  },
};

// Task configuration by lead_type
const taskConfig = {
  hot: {
    text: `Горячий лид ${leadData.public_number}. Связаться с клиентом.`,
    due_minutes: 15,
    create: true
  },
  warm: {
    text: `Тёплый лид ${leadData.public_number}. Выполнить follow-up.`,
    due_minutes: 1440, // 24 hours
    create: true
  },
  cold: {
    text: `Холодный лид ${leadData.public_number}. Отложенный контакт.`,
    due_minutes: 10080, // 7 days
    create: true
  },
  spam: {
    text: '',
    due_minutes: 0,
    create: false
  }
};

const task = taskConfig[leadData.lead_type] || taskConfig.cold;

return [{
  json: {
    lead_id: leadData.lead_id,
    lead_type: leadData.lead_type,
    public_number: leadData.public_number,
    contact_name: leadData.contact_name,
    contact_phone: leadData.contact_phone,
    contact_email: leadData.contact_email,
    summary: leadData.summary,
    reasoning: leadData.reasoning,
    suggested_action: leadData.suggested_action,
    first_message: leadData.first_message,

    is_spam: isSpam,
    create_task: task.create && !isSpam,
    task_text: task.text,
    task_due_minutes: task.due_minutes,

    kommo_payload: kommoPayload,
    kommo_url: `${$env.KOMMO_BASE_URL}/api/v4/leads/complex`,
    kommo_auth: `Bearer ${$env.KOMMO_ACCESS_TOKEN}`,
    kommo_body: [kommoPayload],

    kommo_pipeline_id: KOMMO_PIPELINE_ID,
    kommo_pipeline_name: 'Основная воронка',
    kommo_status_id: statusId,
    kommo_status_name: statusName,
    kommo_responsible_user_id: KOMMO_RESPONSIBLE_USER_ID,
  },
}];

const response = $input.item.json;
const payload = $('Build Kommo Payload').item.json;

// FIX #4: Correctly parse Kommo API response
const parsed = typeof response.data === 'string'
  ? JSON.parse(response.data)
  : response;

// Handle array or single object response
const leadData = Array.isArray(parsed) ? parsed[0] : parsed;
const embeddedLeads = leadData?._embedded?.leads;
const firstLead = Array.isArray(embeddedLeads) ? embeddedLeads[0] : null;

const leadId = firstLead?.id || leadData?.id;
const contactId = leadData?._embedded?.contacts?.[0]?.id;

return [{
  json: {
    lead_id: payload.lead_id,
    lead_type: payload.lead_type,
    public_number: payload.public_number,

    kommo_lead_id: leadId ? leadId.toString() : null,
    kommo_contact_id: contactId ? contactId.toString() : null,

    is_spam: payload.is_spam,
    create_task: payload.create_task,
    task_text: payload.task_text,
    task_due_minutes: payload.task_due_minutes,

    kommo_pipeline_id: payload.kommo_pipeline_id,
    kommo_pipeline_name: payload.kommo_pipeline_name,
    kommo_status_id: payload.kommo_status_id,
    kommo_status_name: payload.kommo_status_name,
    kommo_responsible_user_id: payload.kommo_responsible_user_id,

    kommo_auth: payload.kommo_auth,
    kommo_base_url: $env.KOMMO_BASE_URL,
    kommo_subdomain: $env.KOMMO_SUBDOMAIN,

    summary: payload.summary,
    reasoning: payload.reasoning,
    suggested_action: payload.suggested_action,
    first_message: payload.first_message,

    sync_status: 'success',
    sync_error: null,
    synced_at: new Date().toISOString()
  }
}];

const error = $input.item.json;
const payload = $('Build Kommo Payload').item.json;

const errorMessage = error.error?.message || 
                     error.message || 
                     JSON.stringify(error);

return [{
  json: {
    lead_id: payload.lead_id,
    lead_type: payload.lead_type,
    public_number: payload.public_number,

    kommo_lead_id: null,
    sync_status: 'failed',
    sync_error: errorMessage.substring(0, 500),
    synced_at: null
  }
}];

