// FIX: Restore context after Create Note HTTP Request
// After Create Note, $json is overwritten with Kommo notes API response
// We need to restore the original context from Prepare Success Data

const context = $('Prepare Success Data').item.json;
const noteResponse = $input.item.json;

// Optional: extract note_id for diagnostics
let noteId = null;
try {
  const parsed = typeof noteResponse.data === 'string'
    ? JSON.parse(noteResponse.data)
    : noteResponse;
  noteId = parsed._embedded?.notes?.[0]?.id || parsed.id || null;
} catch (e) {
  // Note creation may have failed, but we continue with original context
}

return [{
  json: {
    ...context,
    note_created: true,
    note_id: noteId
  }
}];

// FIX: Use restored context from 'Restore Context After Note'
const prevData = $('Restore Context After Note').item.json;

return [{
  json: {
    ...prevData,
    initial_task_created: true,
    crm_has_active_task: true,
    crm_closest_task_at: new Date(Date.now() + prevData.task_due_minutes * 60000).toISOString(),
    crm_closed_at: null,
    crm_raw_snapshot: null
  }
}];

// FIX: Use restored context from 'Restore Context After Note'
const prevData = $('Restore Context After Note').item.json;

return [{
  json: {
    ...prevData,
    initial_task_created: false,
    crm_has_active_task: false,
    crm_closest_task_at: null,
    crm_closed_at: prevData.is_spam ? new Date().toISOString() : null,
    crm_raw_snapshot: null
  }
}];

// Prepare Success Log Node
const syncData = $('Insert CRM Sync').item.json;
const statusData = $input.item.json;
const payload = $('Build Kommo Payload').item.json;

return [{
  json: {
    lead_id: syncData.lead_id,
    event_type: 'crm_sync_success',
    event_data: JSON.stringify({
      crm_type: 'kommo',
      kommo_lead_id: syncData.kommo_lead_id,
      public_number: payload.public_number,
      lead_type: payload.lead_type,
      contact_name: payload.contact_name,
      new_status: statusData.status,
      initial_task_created: syncData.initial_task_created
    }),
    status: 'success',
    error_message: null
  }
}];

// Prepare Error Log Node
const syncData = $input.item.json;
const payload = $('Build Kommo Payload').item.json;

return [{
  json: {
    lead_id: syncData.lead_id,
    event_type: 'crm_sync_error',
    event_data: JSON.stringify({
      crm_type: 'kommo',
      sync_error: syncData.sync_error,
      public_number: payload.public_number,
      lead_type: payload.lead_type,
      contact_name: payload.contact_name
    }),
    status: 'error',
    error_message: syncData.sync_error
  }
}];

// Final Success Response
const syncData = $('Insert CRM Sync').item.json;
const logData = $('Insert Log').item.json;
const statusData = $('Update Lead Status').item.json;
const payload = $('Build Kommo Payload').item.json;

const kommoUrl = syncData.kommo_lead_id 
  ? `https://${$env.KOMMO_SUBDOMAIN}.kommo.com/leads/detail/${syncData.kommo_lead_id}`
  : null;

return [{
  json: {
    success: true,
    lead_id: syncData.lead_id,
    kommo_lead_id: syncData.kommo_lead_id,
    kommo_url: kommoUrl,
    public_number: payload.public_number,
    lead_type: payload.lead_type,
    sync_status: syncData.sync_status,
    initial_task_created: syncData.initial_task_created,
    crm_has_active_task: syncData.crm_has_active_task,
    new_lead_status: statusData.status,
    log_id: logData.id,
    synced_at: syncData.created_at
  }
}];

// Final Error Response
const syncData = $('Insert CRM Sync (Error)').item.json;
const logData = $('Insert Log (Error)').item.json;
const payload = $('Build Kommo Payload').item.json;

return [{
  json: {
    success: false,
    lead_id: syncData.lead_id,
    public_number: payload.public_number,
    lead_type: payload.lead_type,
    sync_status: syncData.sync_status,
    sync_error: syncData.sync_error,
    log_id: logData.id,
    created_at: syncData.created_at
  }
}];
